"""Core vocabulary and entities: enums, exceptions, Restaurant, Order."""
from __future__ import annotations

from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, Optional, Tuple


# ── WHY THIS (enums) ─────────────────────────────────────────────────────────
# Plain words to say: "These are just the vocabulary of the system — the legal
# order states, the selection rules a customer can pick, and the menu ops."
class OrderStatus(Enum):
    ACCEPTED = "ACCEPTED"     # assigned to a restaurant, holding one capacity slot
    COMPLETED = "COMPLETED"   # restaurant finished it; slot freed
    REJECTED = "REJECTED"     # no single restaurant could fulfill it


class SelectionCriteria(Enum):
    LOWEST_COST = "LOWEST_COST"
    HIGHEST_RATING = "HIGHEST_RATING"


class MenuUpdate(Enum):
    ADD = "ADD"
    UPDATE = "UPDATE"


# ── WHY (custom exceptions) ──────────────────────────────────────────────────
# 🎙️ "I never raise bare Exception — each failure mode is its own type so the
#      caller (and the interviewer) can see exactly what went wrong."
class FoodOrderingError(Exception):
    """Base class for all domain errors."""


class ValidationError(FoodOrderingError):
    """Bad input at a public boundary (empty basket, qty <= 0, bad rating...)."""


class DuplicateRestaurantError(FoodOrderingError):
    """Onboarding a name that already exists."""


class UnknownRestaurantError(FoodOrderingError):
    """Operating on a restaurant name that was never onboarded."""


class UnknownCriteriaError(FoodOrderingError):
    """Customer asked for a selection rule we have no strategy for."""


class MenuItemError(FoodOrderingError):
    """ADD an item that exists, or UPDATE an item that does not."""


class CapacityError(FoodOrderingError):
    """Reserve when full, or release when already empty — guards the invariant."""


class OrderNotFulfillableError(FoodOrderingError):
    """No single restaurant can serve the whole basket (or all are full)."""
    def __init__(self, order_id: str, message: str) -> None:
        super().__init__(message)
        self.order_id = order_id  # the REJECTED order still exists and is queryable


class UnknownOrderError(FoodOrderingError):
    """complete_order on an id we never issued."""


class InvalidOrderStateError(FoodOrderingError):
    """Illegal transition, e.g. completing a REJECTED or already-COMPLETED order."""


Items = Dict[str, int]  # item name -> quantity


# ── WHY THIS CLASS: Restaurant ───────────────────────────────────────────────
# Restaurant is the capacity STATE MACHINE. It is the ONLY place _active changes,
# so the rule "0 <= _active <= max_orders" can never be broken from outside.
# 🎙️ "This is the heart of the capacity logic. Nobody else touches the active
#      count — they ask the restaurant to reserve or release, and it enforces
#      its own limits."
class Restaurant:
    def __init__(self, name: str, menu: Items, rating: float, max_orders: int) -> None:
        # WHY: validate at construction — a restaurant can never exist in a bad state.
        if not name or not name.strip():
            raise ValidationError("restaurant name must be non-empty")
        if not menu:
            raise ValidationError("menu must have at least one item")
        if any(price <= 0 for price in menu.values()):
            raise ValidationError("all menu prices must be positive")
        if not (1.0 <= rating <= 5.0):
            raise ValidationError("rating must be between 1 and 5")
        if max_orders <= 0:
            raise ValidationError("max_orders must be positive")

        self.name = name
        self.rating = rating
        self.max_orders = max_orders
        self._menu: Items = dict(menu)   # price is an int (rupees) -> no float money bugs
        self._active = 0                 # in-flight ACCEPTED orders

    # --- read-only queries used by the eligibility filter & strategies ---
    def can_fulfill(self, items: Items) -> bool:
        # WHY: single-restaurant rule — every item must be on THIS menu, else out.
        return all(item in self._menu for item in items)

    def price_for(self, items: Items) -> int:
        # WHY: cost of THIS basket here = sum(price * qty). Integer math only.
        # ⚠️ FOLLOW-UP: "What if an item isn't on the menu?"
        #    → "Callers always check can_fulfill first; I still guard with a clear error."
        if not self.can_fulfill(items):
            raise MenuItemError(f"{self.name} cannot serve all requested items")
        return sum(self._menu[item] * qty for item, qty in items.items())

    def has_free_capacity(self) -> bool:
        return self._active < self.max_orders

    # --- capacity mutators (the guarded invariant) ---
    def reserve(self) -> None:
        # WHY: claim one slot. Refuses past the cap so the count can't exceed max.
        if not self.has_free_capacity():
            raise CapacityError(f"{self.name} is at full capacity")
        self._active += 1

    def release(self) -> None:
        # WHY: free a slot on COMPLETED. Refuses to go negative — guards against
        #      a double-complete corrupting the count.
        if self._active == 0:
            raise CapacityError(f"{self.name} has no active orders to release")
        self._active -= 1

    # --- menu maintenance (no delete by spec) ---
    def add_item(self, item: str, price: int) -> None:
        # WHY: ADD means brand-new item; refusing an existing one keeps ADD/UPDATE distinct.
        if price <= 0:
            raise ValidationError("price must be positive")
        if item in self._menu:
            raise MenuItemError(f"{item} already exists; use UPDATE")
        self._menu[item] = price

    def update_item(self, item: str, price: int) -> None:
        if price <= 0:
            raise ValidationError("price must be positive")
        if item not in self._menu:
            raise MenuItemError(f"{item} not on menu; use ADD")
        self._menu[item] = price

    @property
    def active_orders(self) -> int:
        return self._active

    def menu_snapshot(self) -> Items:
        return dict(self._menu)


# ── WHY THIS CLASS: Order ────────────────────────────────────────────────────
# A record of one customer request and its outcome. Items are frozen at creation
# (a tuple) so the basket can't change after the order is placed.
@dataclass
class Order:
    id: str
    user: str
    items: Tuple[Tuple[str, int], ...]            # frozen basket
    status: OrderStatus
    restaurant_name: Optional[str] = None         # set only when ACCEPTED
    total_cost: Optional[int] = None              # set only when ACCEPTED

    @staticmethod
    def freeze(items: Items) -> Tuple[Tuple[str, int], ...]:
        return tuple(sorted(items.items()))

"""Pluggable selection strategies — the extensibility seam (Strategy pattern)."""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Dict, List

from models import Restaurant, ValidationError

Items = Dict[str, int]


# ── WHY THIS CLASS: SelectionStrategy ────────────────────────────────────────
# The pluggable rule for "which eligible restaurant wins". The service depends
# ONLY on this interface, never on a concrete rule — that's what makes new
# criteria a drop-in.
# 🎙️ "Selection is exactly the thing the prompt says must be pluggable, so I
#      pull it behind one interface. The service filters eligible restaurants,
#      then hands them to a strategy to rank."
class SelectionStrategy(ABC):
    @abstractmethod
    def select(self, candidates: List[Restaurant], items: Items) -> Restaurant:
        """Pick ONE restaurant from a non-empty eligible list."""


class LowestCostStrategy(SelectionStrategy):
    def select(self, candidates: List[Restaurant], items: Items) -> Restaurant:
        if not candidates:
            raise ValidationError("no candidates to select from")
        # WHY: cheapest basket wins. Deterministic tie-break: higher rating, then
        #      name — so two equal-cost restaurants always resolve the same way.
        return min(candidates, key=lambda r: (r.price_for(items), -r.rating, r.name))


class HighestRatingStrategy(SelectionStrategy):
    def select(self, candidates: List[Restaurant], items: Items) -> Restaurant:
        if not candidates:
            raise ValidationError("no candidates to select from")
        # WHY: best rating wins. Tie-break: cheaper basket, then name.
        return min(candidates, key=lambda r: (-r.rating, r.price_for(items), r.name))
